import React from 'react';
import './Login.css';

export default function Login({ onLogin }) {
  const [email, setEmail] = React.useState('');
  const [password, setPassword] = React.useState('');
  const [loading, setLoading] = React.useState(false);
  const [error, setError] = React.useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 1000));
      onLogin({ email });
    } catch (err) {
      setError('Invalid credentials. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login">
      {/* Background grid */}
      <div className="login-grid" />
      <div className="login-orb login-orb1" />
      <div className="login-orb login-orb2" />

      {/* Login form container */}
      <main className="login-form-container">
        {/* Logo and title */}
        <div className="login-header">
          <span className="login-logo-mark">✦</span>
          <h1 className="login-title">MediPredict</h1>
          <p className="login-subtitle">AI-powered symptom diagnosis</p>
        </div>

        {/* Login form */}
        <form className="login-form" onSubmit={handleSubmit}>
          {/* Email field */}
          <div className="login-field">
            <label htmlFor="email" className="login-label">
              Email address
            </label>
            <div className="login-input-wrap">
              <svg width="16" height="16" viewBox="0 0 16 16" fill="none" className="login-input-icon">
                <path d="M3 8L8 13L13 8V3H3Z" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                <path d="M8 3V13" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
              </svg>
              <input
                id="email"
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="Enter your email"
                className="login-input"
                required
              />
            </div>
          </div>

          {/* Password field */}
          <div className="login-field">
            <label htmlFor="password" className="login-label">
              Password
            </label>
            <div className="login-input-wrap">
              <svg width="16" height="16" viewBox="0 0 16 16" fill="none" className="login-input-icon">
                <rect x="2" y="4" width="12" height="8" rx="1" stroke="currentColor" strokeWidth="1.5"/>
                <circle cx="8" cy="9" r="1" fill="currentColor"/>
                <path d="M2 2.5C2 2.5 8 1 14 2.5" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round"/>
              </svg>
              <input
                id="password"
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="Enter your password"
                className="login-input"
                required
              />
            </div>
          </div>

          {/* Error message */}
          {error && (
            <div className="login-error">
              {error}
            </div>
          )}

          {/* Submit button */}
          <button
            type="submit"
            className="login-submit"
            disabled={loading}
          >
            {loading ? (
              <>
                <span className="login-spinner" />
                Signing in...
              </>
            ) : (
              "Sign in"
            )}
          </button>

          {/* Footer text */}
          <div className="login-footer">
            <p className="login-footer-text">
              Don't have an account? <a href="#" className="login-link">Sign up</a>
            </p>
            <p className="login-footer-text">
              <a href="#" className="login-link">Forgot password?</a>
            </p>
          </div>
        </form>
      </main>
    </div>
  );
}
